import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [telefono, setTelefono] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  // ESTADOS DE SEGURIDAD 2FA (EMAIL)
  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 

  const abortControllerRef = useRef(null);

  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setEmail(res.data.email);
        setTwoStep(true); 
      }
    } catch (e) { alert("Datos incorrectos"); }
  };

  const verificarOTP = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/verify-otp', { usuario, otp });
      if (res.data.success) {
        setUserRole(res.data.rol);
        setIsLoggedIn(true);
      } else { alert("Código incorrecto"); }
    } catch (e) { alert("Error"); }
  };

  const manejarRecuperacion = async () => {
      try {
          const res = await axios.post('http://localhost:5000/api/recover', { contacto: email || telefono });
          alert(res.data.message);
          setAuthMode('login');
      } catch (e) { alert("Usuario no encontrado"); }
  };

  // --- VISTA LOGIN / 2FA / RECOVERY ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700">

          {twoStep ? (
            /* PASO 2: CÓDIGO POR EMAIL */
            <div className="text-center">
              <i className="fas fa-paper-plane text-[#00c984] text-4xl mb-4"></i>
              <h2 className="text-2xl font-bold text-white mb-2 uppercase">Verificación</h2>
              <p className="text-gray-400 text-[10px] mb-6 uppercase tracking-widest">Enviamos un código a {email}</p>
              <input 
                maxLength="6"
                placeholder="000000"
                className="w-full bg-[#444c56] text-white text-center text-4xl font-black py-4 rounded-3xl outline-none mb-6 tracking-widest"
                onChange={e => setOtp(e.target.value)}
              />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl" onClick={verificarOTP}>CONFIRMAR</button>
            </div>
          ) : (
            /* PASO 1: LOGIN / REGISTRO / RECUPERACIÓN */
            <div className="space-y-4">
              <div className="text-center mb-6">
                <h2 className="text-3xl font-black text-white uppercase tracking-tighter">
                  {authMode === 'login' ? 'Acceso Pro' : authMode === 'register' ? 'Nuevo Registro' : 'Recuperar'}
                </h2>
              </div>

              {authMode !== 'recovery' && (
                  <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
              )}

              {authMode === 'register' && (
                <>
                  <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                  <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Teléfono" onChange={e => setTelefono(e.target.value)} />
                  <select className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                    <option value="vendedor">Vendedor</option>
                    <option value="admin">Administrador</option>
                  </select>
                </>
              )}

              {authMode === 'recovery' && (
                  <>
                  <p className="text-gray-400 text-[10px] text-center uppercase mb-4">Ingresa tu email o teléfono registrado</p>
                  <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Email o Teléfono" onChange={e => setTelefono(e.target.value)} />
                  </>
              )}

              {authMode !== 'recovery' && (
                <input type="password" underline="false" className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              )}

              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-2xl shadow-lg" 
                onClick={authMode === 'login' ? handleLogin : authMode === 'recovery' ? manejarRecuperacion : () => alert("Registrando...")}>
                {authMode.toUpperCase()}
              </button>

              <div className="flex justify-between text-[10px] text-gray-400 font-bold uppercase cursor-pointer pt-2">
                <span onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                  {authMode === 'login' ? 'Regístrate' : 'Login'}
                </span>
                <span onClick={() => setAuthMode('recovery')}>¿Olvidaste clave?</span>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // --- VISTA DASHBOARD (LETRA GIGANTE) ---
  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {view === "dashboard" ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="bg-white p-12 border-2 rounded-[60px] shadow-xl text-center">
              <p className="text-xs text-gray-400 font-black uppercase mb-4 tracking-widest italic">Total Productos</p>
              <p className="text-8xl font-black text-[#1e293b]">{stats.total_productos}</p>
            </div>
            <div className="bg-white p-12 border-2 rounded-[60px] shadow-xl text-center">
              <p className="text-xs text-red-400 font-black uppercase mb-4 tracking-widest italic">Bajo Stock</p>
              <p className="text-8xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-12 border-2 rounded-[60px] shadow-xl text-center">
              <p className="text-xs text-green-400 font-black uppercase mb-4 tracking-widest italic">Valor Total</p>
              <p className="text-6xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          /* VISTA INVENTARIO MANTENIDA */
          <div className="space-y-6">
              <div className="flex justify-between items-center mb-4">
                  <h2 className="text-4xl font-black text-slate-800 uppercase">Inventario</h2>
                  <button onClick={() => setShowForm(!showForm)} className="bg-slate-800 text-white px-8 py-3 rounded-2xl font-black">NUEVO</button>
              </div>
              {/* Formulario y Tabla... */}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
